const charBacktick = "`";
const charCaret = "^";
const charAt = "@";
const charPercent = "%";
const charAmp = "&";
const charHash = "#";
const charExclam = "!";

function safeStr(left, middle, right) {
    return left + middle + right;
}

export function evaluate(code) {
    return eval(code)
}



